class WebSocketServer:
    def __init__(self, port=8080):
        self.port = port
        self.clients = []
        self.server_socket = None
        
    def start(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind(('0.0.0.0', self.port))
        self.server_socket.listen(5)
        self.server_socket.setblocking(False)
        print(f'WebSocket server started on port {self.port}')
        
    def accept_connection(self):
        try:
            client_socket, addr = self.server_socket.accept()
            client_socket.setblocking(False)
            print(f'New connection from {addr}')
            return client_socket, addr
        except OSError:
            return None, None
            
    def handshake(self, client_socket):
        try:
            request = client_socket.recv(1024).decode('utf-8')
            if 'Upgrade: websocket' not in request:
                client_socket.close()
                return False
                
            key = None
            for line in request.split('\r\n'):
                if 'Sec-WebSocket-Key' in line:
                    key = line.split(': ')[1]
                    break
                    
            if not key:
                client_socket.close()
                return False
                
            magic_string = '258EAFA5-E914-47DA-95CA-C5AB0DC85B11'
            accept_key = hashlib.sha1((key + magic_string).encode()).digest()
            accept_key = binascii.b2a_base64(accept_key).decode().strip()
            
            response = 'HTTP/1.1 101 Switching Protocols\r\n'
            response += 'Upgrade: websocket\r\n'
            response += 'Connection: Upgrade\r\n'
            response += f'Sec-WebSocket-Accept: {accept_key}\r\n\r\n'
            
            client_socket.send(response.encode())
            return True
        except Exception as e:
            print(f'Handshake error: {e}')
            return False
            
    def receive_frame(self, client_socket):
        try:
            header = client_socket.recv(2)
            if len(header) < 2:
                return None
                
            opcode = header[0] & 0x0F
            masked = header[1] & 0x80
            payload_length = header[1] & 0x7F
            
            if opcode == 0x8:
                return 'close'
                
            if payload_length == 126:
                extended_length = client_socket.recv(2)
                payload_length = struct.unpack('>H', extended_length)[0]
            elif payload_length == 127:
                extended_length = client_socket.recv(8)
                payload_length = struct.unpack('>Q', extended_length)[0]
                
            if masked:
                masking_key = client_socket.recv(4)
            else:
                return None
                
            payload = bytearray()
            while len(payload) < payload_length:
                chunk = client_socket.recv(payload_length - len(payload))
                if not chunk:
                    break
                payload.extend(chunk)
                
            if len(payload) < payload_length:
                return None
                
            unmasked_payload = bytearray()
            for i in range(len(payload)):
                unmasked_payload.append(payload[i] ^ masking_key[i % 4])
                
            return unmasked_payload.decode('utf-8')
        except OSError:
            return None
        except Exception as e:
            print(f'Receive error: {e}')
            return None
            
    def send_frame(self, client_socket, message):
        try:
            if isinstance(message, str):
                message = message.encode('utf-8')
                
            length = len(message)
            frame = bytearray()
            frame.append(0x81)
            
            if length < 126:
                frame.append(length)
            elif length < 65536:
                frame.append(126)
                frame.extend(struct.pack('>H', length))
            else:
                frame.append(127)
                frame.extend(struct.pack('>Q', length))
                
            frame.extend(message)
            client_socket.send(frame)
            return True
        except Exception as e:
            print(f'Send error: {e}')
            return False
            
    def broadcast(self, message):
        if isinstance(message, dict):
            message = json.dumps(message)
            
        dead_clients = []
        for client in self.clients:
            if not self.send_frame(client, message):
                dead_clients.append(client)
                
        for client in dead_clients:
            self.remove_client(client)
            
    def remove_client(self, client_socket):
        if client_socket in self.clients:
            self.clients.remove(client_socket)
        try:
            client_socket.close()
        except:
            pass
        print(f'Client disconnected. Active clients: {len(self.clients)}')
        
    def handle_message(self, message):
        try:
            data = json.loads(message)
            print(f'Received: {data}')
            
            if 'action' in data:
                action = data['action']
                response = self.process_action(action, data)
                return response
            else:
                return {'status': 'error', 'message': 'No action specified'}
        except json.JSONDecodeError:
            return {'status': 'error', 'message': 'Invalid JSON'}
        except Exception as e:
            return {'status': 'error', 'message': str(e)}
            
    def process_action(self, action, data):
        if action == 'turn_on':
            return {'status': 'success', 'action': 'turn_on', 'state': 'on'}
        elif action == 'turn_off':
            return {'status': 'success', 'action': 'turn_off', 'state': 'off'}
        elif action == 'status':
            return {'status': 'success', 'state': 'unknown'}
        elif action == 'ping':
            return {'status': 'success', 'message': 'pong'}
        else:
            return {'status': 'error', 'message': f'Unknown action: {action}'}
            
    def run(self):
        while True:
            client_socket, addr = self.accept_connection()
            if client_socket:
                if self.handshake(client_socket):
                    self.clients.append(client_socket)
                    print(f'WebSocket connection established. Active clients: {len(self.clients)}')
                    
            dead_clients = []
            for client in self.clients:
                message = self.receive_frame(client)
                if message == 'close' or message is None:
                    if message == 'close':
                        dead_clients.append(client)
                elif message:
                    response = self.handle_message(message)
                    self.send_frame(client, json.dumps(response))
                    
            for client in dead_clients:
                self.remove_client(client)
                
            time.sleep(0.01)


class IoTDevice:
    def __init__(self):
        self.led = Pin(2, Pin.OUT)
        self.state = False
        self.ws_server = WebSocketServer(port=8080)
        
    def setup_wifi(self, ssid, password):
        wlan = network.WLAN(network.STA_IF)
        wlan.active(True)
        if not wlan.isconnected():
            print('Connecting to WiFi...')
            wlan.connect(ssid, password)
            timeout = 0
            while not wlan.isconnected() and timeout < 20:
                time.sleep(1)
                timeout += 1
                
        if wlan.isconnected():
            print('Network config:', wlan.ifconfig())
            return True
        else:
            print('Failed to connect to WiFi')
            return False
            
    def process_action(self, action, data):
        if action == 'turn_on':
            self.led.on()
            self.state = True
            return {'status': 'success', 'action': 'turn_on', 'state': 'on'}
        elif action == 'turn_off':
            self.led.off()
            self.state = False
            return {'status': 'success', 'action': 'turn_off', 'state': 'off'}
        elif action == 'toggle':
            self.state = not self.state
            self.led.value(self.state)
            return {'status': 'success', 'action': 'toggle', 'state': 'on' if self.state else 'off'}
        elif action == 'status':
            return {'status': 'success', 'state': 'on' if self.state else 'off'}
        elif action == 'ping':
            return {'status': 'success', 'message': 'pong'}
        else:
            return {'status': 'error', 'message': f'Unknown action: {action}'}
            
    def start(self, ssid, password):
        if self.setup_wifi(ssid, password):
            self.ws_server.process_action = self.process_action
            self.ws_server.start()
            print('IoT Device ready')
            self.ws_server.run()


def start_iot_device(ssid, password):
    device = IoTDevice()
    device.start(ssid, password)


